+    #[test]
+    fn empty_like_matches_numpy_across_surface_dtype_shape_scalar_and_zero() {
+        with_python(|py| {
+            if !numpy_available(py) {
+                return Ok(());
+            }
+
+            let module = PyModule::new(py, "fnp_python_test")?;
+            fnp_python(&module)?;
+            let empty_like_fn = module.getattr("empty_like")?;
+            let numpy = py.import("numpy")?;
+            let numpy_empty_like = numpy.getattr("empty_like")?;
+
+            // Default dtype/order should follow the input array surface.
+            let fortran_source = numpy
+                .getattr("asfortranarray")?
+                .call1((vec![vec![1_i64, 2, 3], vec![4_i64, 5, 6]],))?;
+            let ours_default = empty_like_fn.call1((fortran_source.clone(),))?;
+            let theirs_default = numpy_empty_like.call1((fortran_source.clone(),))?;
+            assert_eq!(
+                ours_default.getattr("dtype")?.str()?.extract::<String>()?,
+                theirs_default
+                    .getattr("dtype")?
+                    .str()?
+                    .extract::<String>()?
+            );
+            assert_eq!(
+                ours_default.getattr("shape")?.extract::<Vec<usize>>()?,
+                theirs_default.getattr("shape")?.extract::<Vec<usize>>()?
+            );
+            let ours_f: bool = ours_default
+                .getattr("flags")?
+                .get_item("F_CONTIGUOUS")?
+                .extract()?;
+            let theirs_f: bool = theirs_default
+                .getattr("flags")?
+                .get_item("F_CONTIGUOUS")?
+                .extract()?;
+            assert_eq!(ours_f, theirs_f, "default order inheritance mismatch");
+
+            // Explicit dtype override must match NumPy's output surface.
+            let ours_dtype = empty_like_fn.call(
+                (fortran_source.clone(),),
+                Some(&{
+                    let kwargs = PyDict::new(py);
+                    kwargs.set_item("dtype", numpy.getattr("float64")?)?;
+                    kwargs
+                }),
+            )?;
+            let theirs_dtype = numpy_empty_like.call(
+                (fortran_source.clone(),),
+                Some(&{
+                    let kwargs = PyDict::new(py);
+                    kwargs.set_item("dtype", numpy.getattr("float64")?)?;
+                    kwargs
+                }),
+            )?;
+            assert_eq!(
+                ours_dtype.getattr("dtype")?.str()?.extract::<String>()?,
+                theirs_dtype.getattr("dtype")?.str()?.extract::<String>()?
+            );
+            assert_eq!(
+                ours_dtype.getattr("shape")?.extract::<Vec<usize>>()?,
+                theirs_dtype.getattr("shape")?.extract::<Vec<usize>>()?
+            );
+
+            // shape= overrides output shape while preserving order semantics.
+            let ours_shape = empty_like_fn.call(
+                (fortran_source.clone(),),
+                Some(&{
+                    let kwargs = PyDict::new(py);
+                    kwargs.set_item("shape", (3_i64,))?;
+                    kwargs
+                }),
+            )?;
+            let theirs_shape = numpy_empty_like.call(
+                (fortran_source.clone(),),
+                Some(&{
+                    let kwargs = PyDict::new(py);
+                    kwargs.set_item("shape", (3_i64,))?;
+                    kwargs
+                }),
+            )?;
+            assert_eq!(
+                ours_shape.getattr("dtype")?.str()?.extract::<String>()?,
+                theirs_shape.getattr("dtype")?.str()?.extract::<String>()?
+            );
+            assert_eq!(
+                ours_shape.getattr("shape")?.extract::<Vec<usize>>()?,
+                theirs_shape.getattr("shape")?.extract::<Vec<usize>>()?
+            );
+
+            // Scalar input parity should match NumPy's 0-d surface exactly.
+            let ours_scalar = empty_like_fn.call1((7_i64,))?;
+            let theirs_scalar = numpy_empty_like.call1((7_i64,))?;
+            assert_eq!(
+                ours_scalar.getattr("dtype")?.str()?.extract::<String>()?,
+                theirs_scalar.getattr("dtype")?.str()?.extract::<String>()?
+            );
+            assert_eq!(
+                ours_scalar.getattr("shape")?.extract::<Vec<usize>>()?,
+                theirs_scalar.getattr("shape")?.extract::<Vec<usize>>()?
+            );
+
+            // Zero-sized inputs should still preserve dtype/layout parity.
+            let zero_source = numpy.getattr("empty")?.call1(((0_i64, 3_i64),))?;
+            let ours_zero = empty_like_fn.call1((zero_source.clone(),))?;
+            let theirs_zero = numpy_empty_like.call1((zero_source.clone(),))?;
+            assert_eq!(
+                ours_zero.getattr("dtype")?.str()?.extract::<String>()?,
+                theirs_zero.getattr("dtype")?.str()?.extract::<String>()?
+            );
+            assert_eq!(
+                ours_zero.getattr("shape")?.extract::<Vec<usize>>()?,
+                theirs_zero.getattr("shape")?.extract::<Vec<usize>>()?
+            );
+            let ours_zero_c: bool = ours_zero
+                .getattr("flags")?
+                .get_item("C_CONTIGUOUS")?
+                .extract()?;
+            let theirs_zero_c: bool = theirs_zero
+                .getattr("flags")?
+                .get_item("C_CONTIGUOUS")?
+                .extract()?;
+            assert_eq!(ours_zero_c, theirs_zero_c, "zero-sized layout mismatch");
+
+            Ok(())
+        });
+    }
